import React, { FunctionComponent, useState } from "react";
import { ctx } from "../services/Context";
import { Button, H1, H2, Icon } from "@blueprintjs/core";
import { observer } from "mobx-react";
import disconnect from "../images/logout_icon.png";
import { OurToaster } from "./OurToaster";
import { Intent } from "@blueprintjs/core/lib/esm/common/intent";
import { Pending } from "./Pending";

export const Connected: FunctionComponent = observer(() => {
  function logout(): void {
    ctx.store.setName("");
    ctx.store.setRole("");
    OurToaster.show({
      message: "Successfully disconnected.",
      intent: Intent.SUCCESS,
      timeout: 8000
    });
  }
  return (
    <div>
        <nav className="bp3-navbar .modifier">
            <div className="bp3-navbar-group bp3-align-left">
                <div className="bp3-navbar-heading">Blueprint</div>
                <input className="bp3-input" placeholder="Search files..." type="text"/>
            </div>
            <div className="bp3-navbar-group bp3-align-right">
                <button className="bp3-button bp3-minimal bp3-icon-home">Home</button>
                <button className="bp3-button bp3-minimal bp3-icon-document">Files</button>
                <span className="bp3-navbar-divider"></span>
                <Button onClick={() => logout()}>
                    <div className="fx -r center forbes">
                        <img className="logout-icon" alt="disconnect" src={disconnect} />
                        Disconnect
                    </div>
                </Button>
                <button className="bp3-button bp3-minimal bp3-icon-user"></button>
                <button className="bp3-button bp3-minimal bp3-icon-notifications"></button>
                <button className="bp3-button bp3-minimal bp3-icon-cog"></button>
            </div>
        </nav>
      {ctx.store.getRole() === "client" ? (
        "client"
      ) : ctx.store.getRole() === "banker" ? (
        "banquier"
      ) : (
        <Pending />
      )}
    </div>
  );
});
